import{_ as n,o as a,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"伺服器液冷散熱供應鏈圖譜","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/散熱研究/散熱供應鏈圖譜.md","filePath":"Deep32Q知識庫/產業洞察/散熱研究/散熱供應鏈圖譜.md"}'),e={name:"Deep32Q知識庫/產業洞察/散熱研究/散熱供應鏈圖譜.md"};function r(l,t,p,i,o,h){return a(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="伺服器液冷散熱供應鏈圖譜" tabindex="-1">伺服器液冷散熱供應鏈圖譜 <a class="header-anchor" href="#伺服器液冷散熱供應鏈圖譜" aria-label="Permalink to &quot;伺服器液冷散熱供應鏈圖譜&quot;">​</a></h1><p><strong>建立日期</strong>：2026-05-06 <strong>研究範圍</strong>：全球資料中心液冷產業鏈（晶片封裝→冷板→CDU→資料中心級） <strong>目標視角</strong>：台灣投資人</p><hr><h2 id="一、全球散熱產業鏈地圖" tabindex="-1">一、全球散熱產業鏈地圖 <a class="header-anchor" href="#一、全球散熱產業鏈地圖" aria-label="Permalink to &quot;一、全球散熱產業鏈地圖&quot;">​</a></h2><h3 id="_1-1-層級架構-由晶片至資料中心" tabindex="-1">1.1 層級架構（由晶片至資料中心） <a class="header-anchor" href="#_1-1-層級架構-由晶片至資料中心" aria-label="Permalink to &quot;1.1 層級架構（由晶片至資料中心）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  資料中心級（Data Center Level）                              │</span></span>
<span class="line"><span>│  ┌─────────┐  ┌─────────┐  ┌─────────┐                     │</span></span>
<span class="line"><span>│  │ 冷卻塔   │  │ CDU    │  │ 分歧管   │  ← 基礎設施層       │</span></span>
<span class="line"><span>│  └────┬────┘  └────┬────┘  └────┬────┘                     │</span></span>
<span class="line"><span>│       └───────────┼─────────────┘                          │</span></span>
<span class="line"><span>├──────────────────┼─────────────────────────────────────────┤</span></span>
<span class="line"><span>│  機櫃級（Rack Level）                                       │</span></span>
<span class="line"><span>│  ┌─────────┐  ┌─────────┐  ┌─────────┐                     │</span></span>
<span class="line"><span>│  │ 水冷機櫃 │  │ 液冷管路 │  │ UQD接頭 │  ← 系統整合層     │</span></span>
<span class="line"><span>│  └────┬────┘  └─────────┘  └─────────┘                     │</span></span>
<span class="line"><span>│       └───────────┼─────────────┘                          │</span></span>
<span class="line"><span>├──────────────────┼─────────────────────────────────────────┤</span></span>
<span class="line"><span>│  計算托盤級（Compute Tray Level）                             │</span></span>
<span class="line"><span>│  ┌─────────┐  ┌─────────┐  ┌─────────┐                     │</span></span>
<span class="line"><span>│  │ 冷卻液   │  │ 分歧管   │  │ 快速接頭│  ← 散熱模組層     │</span></span>
<span class="line"><span>│  └────┬────┘  └─────────┘  └─────────┘                     │</span></span>
<span class="line"><span>│       └───────────┼─────────────┘                          │</span></span>
<span class="line"><span>├──────────────────┼─────────────────────────────────────────┤</span></span>
<span class="line"><span>│  晶片級（Chip Level）                                       │</span></span>
<span class="line"><span>│  ┌─────────┐  ┌─────────┐  ┌─────────┐                     │</span></span>
<span class="line"><span>│  │ 冷板    │  │ LTM導熱  │  │ 液態金屬│  ← 直接接觸散熱   │</span></span>
<span class="line"><span>│  └────┬────┘  └─────────┘  └─────────┘                     │</span></span>
<span class="line"><span>│       └───────────┼─────────────┘                          │</span></span>
<span class="line"><span>├──────────────────┼─────────────────────────────────────────┤</span></span>
<span class="line"><span>│  封裝級（Package Level）                                    │</span></span>
<span class="line"><span>│  ┌─────────┐  ┌─────────┐  ┌─────────┐                     │</span></span>
<span class="line"><span>│  │ GPU/CPU │  │ MCL微通道│  │ IHS均熱片│  ← 封裝創新       │</span></span>
<span class="line"><span>│  └─────────┘  └─────────┘  └─────────┘                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="_1-2-各層級關鍵元件與供應商" tabindex="-1">1.2 各層級關鍵元件與供應商 <a class="header-anchor" href="#_1-2-各層級關鍵元件與供應商" aria-label="Permalink to &quot;1.2 各層級關鍵元件與供應商&quot;">​</a></h3><table tabindex="0"><thead><tr><th>層級</th><th>關鍵元件</th><th>主要供應商（台廠）</th><th>主要供應商（國際）</th></tr></thead><tbody><tr><td><strong>晶片級</strong></td><td>冷板（Cold Plate）</td><td>奇鋐(3017)、雙鴻(3324)</td><td>Asetek、Boondy、nVent</td></tr><tr><td></td><td>液態金屬介面材料（LTM）</td><td>富世達(6841)</td><td>Cooper Industries、Honeywell</td></tr><tr><td></td><td>MCL微通道冷板（開發中）</td><td>奇鋐、雙鴻（試產階段）</td><td>AMD、台積電（封裝內建）</td></tr><tr><td></td><td>LITE-ON GB300冷板（2026量產）</td><td>6,200W散熱、4x GPU+2x CPU</td><td>LITE-ON自主開發</td></tr><tr><td><strong>機櫃級</strong></td><td>分歧管（Manifold）</td><td>奇鋐、雙鴻、台達電(2308)</td><td>nVent、Boondy</td></tr><tr><td></td><td>UQD快速接頭（v2標準化）</td><td>雙鴻、奇鋐</td><td>nVent (Stäubli)、Boondy</td></tr><tr><td></td><td>CDU（冷卻分配單元）</td><td>雙鴻、台達電、晟銘電(3013)</td><td>nVent、Boondy、Schneider</td></tr><tr><td></td><td><strong>台達電3MW L2L CDU</strong>（2026）</td><td>3000kW散熱/3000LPM</td><td>台達電自主開發</td></tr><tr><td></td><td>泵浦（Pump）</td><td>建準(2421)自製開發中</td><td>Grundfos、Ebara</td></tr><tr><td><strong>資料中心級</strong></td><td>冷卻塔/乾冷器</td><td>台達電、奇鋐</td><td>Schneider、Vertiv</td></tr><tr><td></td><td>冷卻液（Coolant）</td><td>—</td><td>3M Novec、Shell、DuPont</td></tr><tr><td></td><td><strong>市場領導者</strong></td><td>—</td><td>Vertiv、CoolIT、nVent、Boyd、Aaon（快速成長）</td></tr></tbody></table><hr><h2 id="二、nvidia-液冷供應鏈層層拆解" tabindex="-1">二、NVIDIA 液冷供應鏈層層拆解 <a class="header-anchor" href="#二、nvidia-液冷供應鏈層層拆解" aria-label="Permalink to &quot;二、NVIDIA 液冷供應鏈層層拆解&quot;">​</a></h2><h3 id="_2-1-gb300-架構-當前主力" tabindex="-1">2.1 GB300 架構（當前主力） <a class="header-anchor" href="#_2-1-gb300-架構-當前主力" aria-label="Permalink to &quot;2.1 GB300 架構（當前主力）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NVIDIA Grace-Blackwell B300 GPU (TDP 1,400W)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── 液態金屬介面材料（73 W/m·K）→ 富世達(6841)</span></span>
<span class="line"><span>    │       ↓</span></span>
<span class="line"><span>    ├── 獨立小型冷板 × 6/計算托盤 → 奇鋐(3017) 40~50%市佔</span></span>
<span class="line"><span>    │       ├── 鍍鎳防腐處理</span></span>
<span class="line"><span>    │       └── 雙相D2C冷卻（2026-2027大規模採用）</span></span>
<span class="line"><span>    │       ↓</span></span>
<span class="line"><span>    ├── 分歧管（Manifold）→ 奇鋐、雙鴻(3324)</span></span>
<span class="line"><span>    │       ↓</span></span>
<span class="line"><span>    ├── UQD v2 快速接頭 → 雙鴻(3324)</span></span>
<span class="line"><span>    │       ↓</span></span>
<span class="line"><span>    └── CDU（列間冷卻分配器）→ 台達電(2308)、雙鴻(3324)</span></span>
<span class="line"><span>            ↓</span></span>
<span class="line"><span>        冷卻塔/乾冷器 → 資料中心基礎設施</span></span></code></pre></div><h3 id="_2-2-vera-rubin-架構-下一代-100-液冷" tabindex="-1">2.2 Vera Rubin 架構（下一代，100%液冷） <a class="header-anchor" href="#_2-2-vera-rubin-架構-下一代-100-液冷" aria-label="Permalink to &quot;2.2 Vera Rubin 架構（下一代，100%液冷）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VR200 GPU (TDP 2,300W) + Rubin GPU (TDP 1,800W)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├── MCL微通道冷板（晶片下方蝕刻微米級水道）→ 奇鋐、雙鴻試產中</span></span>
<span class="line"><span>    │       ├── 2026下半年單晶片版 Rubin 應用</span></span>
<span class="line"><span>    │       └── 2027年量產 Rubin Ultra (~3,000W)</span></span>
<span class="line"><span>    │       ↓</span></span>
<span class="line"><span>    ├── 大型冷板設計（每計算托盤）→ 奇鋐、雙鴻</span></span>
<span class="line"><span>    │       ├── 內部MQD（微型快速接頭）</span></span>
<span class="line"><span>    │       └── 內部歧管系統</span></span>
<span class="line"><span>    │       ↓</span></span>
<span class="line"><span>    ├── POWER RACK（獨立電源機櫃，100%液冷）→ 台達電(2308)</span></span>
<span class="line"><span>    │       ↓</span></span>
<span class="line"><span>    └── 無風扇模組化設計 → 晟銘電(3013) Sidecar技術</span></span></code></pre></div><h3 id="_2-3-台灣廠商在-nvidia-供應鏈中的地位" tabindex="-1">2.3 台灣廠商在 NVIDIA 供應鏈中的地位 <a class="header-anchor" href="#_2-3-台灣廠商在-nvidia-供應鏈中的地位" aria-label="Permalink to &quot;2.3 台灣廠商在 NVIDIA 供應鏈中的地位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>台廠</th><th>GB200</th><th>GB300</th><th>Vera Rubin</th><th>預估市佔率</th></tr></thead><tbody><tr><td><strong>奇鋐(3017)</strong></td><td>主力供應商</td><td>40~50%（水冷板）</td><td>預期 &gt;55%長期目標</td><td>最大受惠者</td></tr><tr><td><strong>雙鴻(3324)</strong></td><td>供應商之一</td><td>GB300認證取得</td><td>Group A三~四家之一</td><td>快速追趕</td></tr><tr><td><strong>台達電(2308)</strong></td><td>CDU/系統整合</td><td>系統級方案+3MW L2L CDU</td><td>電源機櫃100%液冷、800VDC</td><td>系統級龍頭</td></tr><tr><td><strong>建準(2421)</strong></td><td>風冷為主</td><td>模組化液冷發表</td><td>待觀察</td><td>轉型中</td></tr><tr><td><strong>晟銘電(3013)</strong></td><td>—</td><td>Sidecar水冷機櫃</td><td>廣達合作Meta訂單</td><td>新進者</td></tr><tr><td><strong>富世達(6841)</strong></td><td>LTM材料</td><td>液態金屬介面</td><td>持續供應</td><td>材料龍頭</td></tr><tr><td><strong>Auras(3324)</strong></td><td>伺服器散熱佔比36.37%（Q1）</td><td>液冷&gt;55%</td><td>Group A供應商之一</td><td>Meta、AWS、微軟</td></tr><tr><td><strong>Microloops</strong></td><td>中國+越南擴產</td><td>ASIC伺服器液冷放量</td><td>2026放量</td><td>CSP多客戶</td></tr></tbody></table><hr><h2 id="三、台灣廠商全球競爭優勢比較" tabindex="-1">三、台灣廠商全球競爭優勢比較 <a class="header-anchor" href="#三、台灣廠商全球競爭優勢比較" aria-label="Permalink to &quot;三、台灣廠商全球競爭優勢比較&quot;">​</a></h2><h3 id="_3-1-奇鋐-3017-vs-雙鴻-3324" tabindex="-1">3.1 奇鋐（3017）vs 雙鴻（3324） <a class="header-anchor" href="#_3-1-奇鋐-3017-vs-雙鴻-3324" aria-label="Permalink to &quot;3.1 奇鋐（3017）vs 雙鴻（3324）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>比較項目</th><th>奇鋐(3017)</th><th>雙鴻(3324)</th></tr></thead><tbody><tr><td><strong>核心優勢</strong></td><td>水冷板市佔40~50%、規模最大</td><td>系統級方案（CDU+歧管+冷板）</td></tr><tr><td><strong>NVIDIA地位</strong></td><td>GB200/GB300主力、Rubin長期&gt;55%</td><td>GB300認證、Group A三~四家之一</td></tr><tr><td><strong>其他客戶</strong></td><td>Google TPU V8（2026 Q3供貨）</td><td>Meta、AWS、微軟</td></tr><tr><td><strong>技術布局</strong></td><td>MCCP試產、MCL開發中</td><td>MCL製程已突破、CDU產線規劃</td></tr><tr><td><strong>產能</strong></td><td>2026年底月產100萬件（越南+中國）</td><td>泰國廠滿載、二期建廠中</td></tr><tr><td><strong>2026營收預估</strong></td><td>YoY+100%+（3月創歷史新高YoY+112%）</td><td>YoY+50%+、伺服器佔比72%</td></tr><tr><td><strong>大摩目標價</strong></td><td>2,750元（4月上調）</td><td>1,080元（下修，Rubin能見度不明）</td></tr></tbody></table><h3 id="_3-2-建準-2421-與台達電-2308" tabindex="-1">3.2 建準（2421）與台達電（2308） <a class="header-anchor" href="#_3-2-建準-2421-與台達電-2308" aria-label="Permalink to &quot;3.2 建準（2421）與台達電（2308）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>比較項目</th><th>建準(2421)</th><th>台達電(2308)</th></tr></thead><tbody><tr><td><strong>定位</strong></td><td>轉型「電子訊號傳輸整合散熱」</td><td>AI基礎設施骨幹、系統級方案</td></tr><tr><td><strong>液冷進展</strong></td><td>2026 Q1營收創新高、OCP展會發表模組化液冷</td><td>800V高壓直流系統、百萬瓦級CDU</td></tr><tr><td><strong>垂直整合</strong></td><td>自製CDU內部泵浦開發中</td><td>穩坐AI伺服器電源60%市佔</td></tr><tr><td><strong>2026展望</strong></td><td>風險報酬比中性（大摩）</td><td>液冷產品為營運主引擎</td></tr></tbody></table><hr><h2 id="四、材料供應商生態系" tabindex="-1">四、材料供應商生態系 <a class="header-anchor" href="#四、材料供應商生態系" aria-label="Permalink to &quot;四、材料供應商生態系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>材料類別</th><th>關鍵產品</th><th>台廠角色</th><th>國際廠商</th></tr></thead><tbody><tr><td><strong>導熱介面材料</strong></td><td>液態金屬（73 W/m·K）</td><td>富世達(6841) — LTM材料龍頭</td><td>Cooper Thermal、Honeywell</td></tr><tr><td><strong>冷卻液</strong></td><td>溫水冷卻（45~65°C回流）</td><td>尚未有台廠主力投入</td><td>3M Novec、Shell、DuPont</td></tr><tr><td><strong>泵浦</strong></td><td>CDU內部循環泵浦</td><td>建準(2421)開發中、台達電3MW L2L內建</td><td>Grundfos、Ebara</td></tr><tr><td><strong>冷板材料</strong></td><td>鍍鎳銅合金/不鏽鋼管</td><td>奇鋐、雙鴻、LITE-ON自主加工</td><td>—</td></tr><tr><td><strong>密封材料</strong></td><td>UQD接頭密封圈</td><td>奇鋐、雙鴻自主設計</td><td>nVent (Stäubli)</td></tr><tr><td><strong>市場領導者</strong></td><td>液冷系統整合</td><td>—</td><td>Vertiv、CoolIT、nVent、Boyd、Aaon（快速成長）</td></tr></tbody></table><hr><h2 id="五、產業標準與生態系成熟度" tabindex="-1">五、產業標準與生態系成熟度 <a class="header-anchor" href="#五、產業標準與生態系成熟度" aria-label="Permalink to &quot;五、產業標準與生態系成熟度&quot;">​</a></h2><ul><li><strong>UQD v2 標準化</strong>：NVIDIA推動快速接頭標準，零組件規模化</li><li><strong>OCP MGX規範</strong>：72 psig最大操作壓力、217 psig最小爆破壓力</li><li><strong>溫水冷卻趨勢</strong>：45~65°C冷卻液回流，降低PUE至1.02~1.15</li><li><strong>系統級價值提升</strong>：從單一冷板→CDU+分歧管+泵浦的完整系統方案</li></ul><hr><h2 id="資料來源" tabindex="-1">資料來源 <a class="header-anchor" href="#資料來源" aria-label="Permalink to &quot;資料來源&quot;">​</a></h2><ol><li>MarketsandMarkets (2026-05): Data Center Liquid Cooling Market $4.07B→$27.65B CAGR 31.5%</li><li>Global Market Insights (2026-05): $4.8B→$27.1B by 2035, CAGR 18.2%</li><li>Mordor Intelligence (2026-05): $6.77B (2026)→$18.79B (2031), CAGR 22.65%</li><li>Persistence Market Research (2026-05): Cold plate &gt;55% share ($3.1B)</li><li>Roots Analysis (2026-05): Immersion cooling $657M→$7B by 2035, CAGR 30.07%</li><li>SemiAnalysis (2026-04): Vera Rubin liquid cooling architecture deep dive</li><li>Global Semi Research (2026-04): NVIDIA liquid cooling analysis GB200→Rubin</li><li>TechNews (2026-04-16): 大摩調升奇鋐至2,750元、富世達至2,150元</li><li>鉅亨網/優分析 (2026-04-18): 2026液冷滲透率76%、單櫃產值跳升4倍</li><li>聯合報 (2026-03): 雙鴻法說會、液冷佔比&gt;55%</li><li><strong>Digitimes (2026-04)</strong>: 奇鋐Q3營收預估NT$32B（YoY+69%）、散熱廠3月創新高</li><li><strong>Digitimes (2026-03)</strong>: 奇鋐2026大幅擴產液冷、太空級冷板測試中</li><li><strong>PRNewswire (2026-04)</strong>: 台達電GTC發表3MW L2L CDU、800VDC架構</li><li><strong>S&amp;P Global (2026-05)</strong>: 台達電Q1營收CNY 159.35B、液冷佔比9%</li><li>LITE-ON GB300 Cold Plate Spec Sheet (2026): 6,200W散熱、UQD接頭</li><li><strong>Dell&#39;Oro Group (2026-01)</strong>: 市場領導者Vertiv、CoolIT、nVent、Boyd</li></ol>`,31)])])}const b=n(e,[["render",r]]);export{g as __pageData,b as default};
